second-highest-no-limit.sql:
SELECT MAX(amount) AS second_highest
FROM salaries
WHERE amount < (SELECT MAX(amount) FROM salaries);

SELECT MAX(amount) AS second_highest
FROM salaries
WHERE amount NOT IN (SELECT MAX(amount) FROM salaries);

customers-with-no-orders.sql:
SELECT name
FROM customers c
WHERE NOT EXISTS (
  SELECT 1 FROM orders o WHERE o.customer_id = c.id
)
ORDER BY name;

nulls-last.sql:
SELECT name, last_seen
FROM contacts
ORDER BY last_seen IS NULL, last_seen DESC;

multi-key-ordering.sql:
SELECT dept, name, salary
FROM employees
ORDER BY dept ASC, salary DESC, name ASC;
